// Instead of sampling E and conditioning, we compute P(E|relation,cp,b) 
// and observe E directly using that marginal probability

var model = function() {
  var relation = flip(0.5);
  var cp = uniform(0, 1);
  var b = uniform(0, 1);

  // Compute marginal probability of E given relation, cp, b
  // E = (relation && C && flip(cp)) || flip(b)
  // With C = true (observed):
  // E = (relation && flip(cp)) || flip(b)

  var probE = function(relation, cp, b) {
    // P(E=true) = P((relation && flip(cp)) || flip(b))
    //           = P(relation && flip(cp)) + P(flip(b)) - P(relation && flip(cp) && flip(b))
    // If relation is true:
    //   P(E=true) = cp + b - cp*b
    // If relation is false:
    //   P(E=true) = b

    if (relation) {
      return cp + b - cp * b;
    } else {
      return b;
    }
  };

  var pE = probE(relation, cp, b);

  // Observe E=false with probability (1 - pE)
  observe(Bernoulli({p: 1 - pE}), 1);

  return {relation: relation, cp: cp, b: b};
};

